parameters.inputSchema:
{
  "type": "object",
  "properties": {
    "strategic_segment": {
      "type": "string",
      "enum": ["churn_risk", "expansion", "neutral"],
      "description": "The strategic segment this customer belongs to"
    },
    "engagement_level": {
      "type": "string",
      "enum": ["high_touch", "low_touch"],
      "description": "Whether this customer requires human CSM intervention or can be handled via automation"
    },
    "confidence": {
      "type": "string",
      "enum": ["high", "medium", "low"],
      "description": "Confidence level in this decision"
    },
    "primary_insight": {
      "type": "string",
      "description": "One key observation driving this decision (1-2 sentences)"
    },
    "key_risks": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Specific risks identified"
    },
    "key_opportunities": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Growth signals or positive indicators"
    },
    "recommended_next_steps": {
      "type": "array",
      "items": {
        "type": "string"
      },
      "description": "Specific actions to take"
    },
    "urgency_level": {
      "type": "string",
      "enum": ["immediate", "high", "moderate", "low"],
      "description": "How quickly action needs to be taken"
    },
    "reasoning_for_touch_level": {
      "type": "string",
      "description": "Brief explanation why high-touch or low-touch was chosen (1 sentence)"
    }
  },
  "required": [
    "strategic_segment",
    "engagement_level",
    "confidence",
    "primary_insight",
    "key_risks",
    "key_opportunities",
    "recommended_next_steps",
    "urgency_level",
    "reasoning_for_touch_level"
  ]
}

